  1	#!/usr/bin/env node
  2	
  3	import dotenv from "dotenv";
  4	import OpenAI from "openai";
  5	import { execFile } from "node:child_process";
  6	import { clearLine, cursorTo, emitKeypressEvents } from "node:readline";
  7	import readline from "node:readline/promises";
  8	import { existsSync, mkdirSync, readFileSync, writeFileSync } from "node:fs";
  9	import { mkdtemp, readFile, rm } from "node:fs/promises";
 10	import { homedir, tmpdir } from "node:os";
 11	import { dirname, join, relative } from "node:path";
 12	import { stdin as input, stdout as output } from "node:process";
 13	import { promisify } from "node:util";
 14	import { fileURLToPath } from "node:url";
 15	
 16	type ChatMessage = OpenAI.Chat.Completions.ChatCompletionMessageParam;
 17	
 18	type SearchResult = {
 19	  title: string;
 20	  url: string;
 21	  snippet: string;
 22	};
 23	
 24	type WebPage = SearchResult & {
 25	  text: string;
 26	  fetched: boolean;
 27	  error?: string;
 28	};
 29	
 30	type RayaResponse = {
 31	  answer: string;
 32	  inputTokens: number;
 33	  outputTokens: number;
 34	  seconds: number;
 35	};
 36	
 37	type ImageAttachment = {
 38	  id: number;
 39	  placeholder: string;
 40	  dataUrl: string;
 41	};
 42	
 43	type TurnInput = {
 44	  text: string;
 45	  attachments: ImageAttachment[];
 46	};
 47	
 48	type RayaConfig = {
 49	  model: string;
 50	  models: string[];
 51	  mode: "Chat" | "Agent";
 52	  contextTokens: number;
 53	  search: {
 54	    maxResults: number;
 55	    pageChars: number;
 56	    fetchTimeoutMs: number;
 57	  };
 58	  images: {
 59	    maxDimension: number;
 60	    jpegQuality: number;
 61	  };
 62	  retries: {
 63	    maxAttempts: number;
 64	    initialDelayMs: number;
 65	  };
 66	  openrouter: {
 67	    apiKey?: string;
 68	    baseURL: string;
 69	    referer: string;
 70	    title: string;
 71	  };
 72	};
 73	
 74	type LoadedConfig = {
 75	  config: RayaConfig;
 76	  paths: string[];
 77	};
 78	
 79	const __dirname = dirname(fileURLToPath(import.meta.url));
 80	const packageRoot = join(__dirname, "..");
 81	const execFileAsync = promisify(execFile);
 82	
 83	const defaultConfig: RayaConfig = {
 84	  model: "google/gemma-4-31b-it:free",
 85	  models: [
 86	    "google/gemma-4-31b-it:free",
 87	    "openai/gpt-4o-mini",
 88	    "anthropic/claude-3.5-sonnet",
 89	    "google/gemini-2.0-flash-001"
 90	  ],
 91	  mode: "Chat",
 92	  contextTokens: 128000,
 93	  search: {
 94	    maxResults: 5,
 95	    pageChars: 6000,
 96	    fetchTimeoutMs: 8000
 97	  },
 98	  images: {
 99	    maxDimension: 1280,
100	    jpegQuality: 80
101	  },
102	  retries: {
103	    maxAttempts: 3,
104	    initialDelayMs: 1200
105	  },
106	  openrouter: {
107	    baseURL: "https://openrouter.ai/api/v1",
108	    referer: "https://github.com/haos/raya-agent",
109	    title: "Raya"
110	  }
111	};
112	
113	const theme = {
114	  reset: "\x1b[0m",
115	  dim: "\x1b[2m",
116	  blue: "\x1b[38;5;67m",
117	  cyan: "\x1b[38;5;109m",
118	  orange: "\x1b[38;5;214m",
119	  red: "\x1b[38;5;167m",
120	  white: "\x1b[38;5;252m",
121	  muted: "\x1b[38;5;242m"
122	} as const;
123	
124	function color(value: string, ...codes: string[]): string {
125	  return `${codes.join("")}${value}${theme.reset}`;
126	}
127	
128	function formatPath(path: string): string {
129	  const home = homedir();
130	
131	  if (path === home) {
132	    return "~";
133	  }
134	
135	  if (path.startsWith(`${home}/`)) {
136	    return `~/${relative(home, path)}`;
137	  }
138	
139	  return path;
140	}
141	
142	function loadEnv(): string | undefined {
143	  const envPaths = [
144	    join(process.cwd(), ".env"),
145	    join(homedir(), ".raya", ".env"),
146	    join(packageRoot, ".env")
147	  ];
148	
149	  for (const envPath of envPaths) {
150	    if (!existsSync(envPath)) {
151	      continue;
152	    }
153	
154	    dotenv.config({ path: envPath, override: false });
155	    return envPath;
156	  }
157	
158	  return undefined;
159	}
160	
161	function isRecord(value: unknown): value is Record<string, unknown> {
162	  return typeof value === "object" && value !== null && !Array.isArray(value);
163	}
164	
165	function optionalString(value: unknown): string | undefined {
166	  return typeof value === "string" && value.length > 0 ? value : undefined;
167	}
168	
169	function optionalNumber(value: unknown): number | undefined {
170	  return typeof value === "number" && Number.isFinite(value) && value > 0 ? value : undefined;
171	}
172	
173	function optionalStringArray(value: unknown): string[] | undefined {
174	  if (!Array.isArray(value)) {
175	    return undefined;
176	  }
177	
178	  const strings = value.filter((item): item is string => typeof item === "string" && item.length > 0);
179	  return strings.length > 0 ? strings : undefined;
180	}
181	
182	function mergeConfig(base: RayaConfig, raw: unknown): RayaConfig {
183	  if (!isRecord(raw)) {
184	    return base;
185	  }
186	
187	  const search = isRecord(raw.search) ? raw.search : undefined;
188	  const images = isRecord(raw.images) ? raw.images : undefined;
189	  const retries = isRecord(raw.retries) ? raw.retries : undefined;
190	  const openrouter = isRecord(raw.openrouter) ? raw.openrouter : undefined;
191	  const mode = raw.mode === "Agent" || raw.mode === "Chat" ? raw.mode : base.mode;
192	  const apiKey = optionalString(openrouter?.apiKey) ?? base.openrouter.apiKey;
193	
194	  return {
195	    ...base,
196	    model: optionalString(raw.model) ?? base.model,
197	    models: optionalStringArray(raw.models) ?? base.models,
198	    mode,
199	    contextTokens: optionalNumber(raw.contextTokens) ?? base.contextTokens,
200	    search: {
201	      ...base.search,
202	      maxResults: optionalNumber(search?.maxResults) ?? base.search.maxResults,
203	      pageChars: optionalNumber(search?.pageChars) ?? base.search.pageChars,
204	      fetchTimeoutMs: optionalNumber(search?.fetchTimeoutMs) ?? base.search.fetchTimeoutMs
205	    },
206	    images: {
207	      ...base.images,
208	      maxDimension: optionalNumber(images?.maxDimension) ?? base.images.maxDimension,
209	      jpegQuality: optionalNumber(images?.jpegQuality) ?? base.images.jpegQuality
210	    },
211	    retries: {
212	      ...base.retries,
213	      maxAttempts: optionalNumber(retries?.maxAttempts) ?? base.retries.maxAttempts,
214	      initialDelayMs: optionalNumber(retries?.initialDelayMs) ?? base.retries.initialDelayMs
215	    },
216	    openrouter: {
217	      ...base.openrouter,
218	      ...(apiKey ? { apiKey } : {}),
219	      baseURL: optionalString(openrouter?.baseURL) ?? base.openrouter.baseURL,
220	      referer: optionalString(openrouter?.referer) ?? base.openrouter.referer,
221	      title: optionalString(openrouter?.title) ?? base.openrouter.title
222	    }
223	  };
224	}
225	
226	function readConfigFile(path: string): unknown {
227	  return JSON.parse(readFileSync(path, "utf8")) as unknown;
228	}
229	
230	function ensureGlobalConfig(path: string): void {
231	  if (existsSync(path)) {
232	    return;
233	  }
234	
235	  mkdirSync(dirname(path), { recursive: true });
236	  writeFileSync(path, `${JSON.stringify(defaultConfig, null, 2)}\n`, { mode: 0o600 });
237	}
238	
239	function loadConfig(): LoadedConfig {
240	  const globalConfigPath = join(homedir(), ".raya", "config.json");
241	  const configPaths = [globalConfigPath, join(process.cwd(), ".raya", "config.json"), join(process.cwd(), "raya.config.json")];
242	  let config = defaultConfig;
243	  const loadedPaths: string[] = [];
244	
245	  ensureGlobalConfig(globalConfigPath);
246	
247	  for (const configPath of configPaths) {
248	    if (!existsSync(configPath)) {
249	      continue;
250	    }
251	
252	    try {
253	      config = mergeConfig(config, readConfigFile(configPath));
254	      loadedPaths.push(configPath);
255	    } catch (error) {
256	      const message = error instanceof Error ? error.message : String(error);
257	      console.error(color(`Invalid config file: ${configPath}`, theme.red));
258	      console.error(message);
259	      process.exit(1);
260	    }

