790	async function readInteractiveInput(): Promise<TurnInput | undefined> {
791	  return new Promise((resolve) => {
792	    let buffer = "";
793	    const attachments: ImageAttachment[] = [];
794	    let suggestionsVisible = false;
795	
796	    const cleanup = (): void => {
797	      input.off("keypress", onKeypress);
798	      input.setRawMode(false);
799	    };
800	
801	    const redraw = (): void => {
802	      renderPrompt(buffer);
803	    };
804	
805	    const appendText = (text: string): void => {
806	      buffer += text;
807	      redraw();
808	    };
809	
810	    const appendImage = async (): Promise<boolean> => {
811	      try {
812	        const dataUrl = await clipboardImageToDataUrl();
813	        const id = attachments.length + 1;
814	        const placeholder = `[Image ${id}]`;
815	        attachments.push({ id, placeholder, dataUrl });
816	        buffer += buffer.length > 0 && !buffer.endsWith(" ") ? ` ${placeholder}` : placeholder;
817	        redraw();
818	        return true;
819	      } catch {
820	        return false;
821	      }
822	    };
823	
824	    const pasteClipboard = async (): Promise<void> => {
825	      if (await appendImage()) {
826	        return;
827	      }
828	
829	      const text = await clipboardText();
830	
831	      if (text.length > 0) {
832	        appendText(text);
833	      }
834	    };
835	
836	    const showSuggestions = (): void => {
837	      if (suggestionsVisible) {
838	        return;
839	      }
840	
841	      suggestionsVisible = true;
842	      printCommandSuggestions();
843	      redraw();
844	    };
845	
846	    const onKeypress = (character: string | undefined, key: { name?: string; ctrl?: boolean; sequence?: string }): void => {
847	      if (key.ctrl && key.name === "c") {
848	        cleanup();
849	        console.log(color("\nBye.", theme.blue));
850	        process.exit(0);
851	      }
852	
853	      if (key.name === "return") {
854	        cleanup();
855	        console.log();
856	        resolve({ text: buffer, attachments: attachments.filter((attachment) => buffer.includes(attachment.placeholder)) });
857	        return;
858	      }
859	
860	      if (key.name === "backspace") {
861	        buffer = buffer.slice(0, -1);
862	        redraw();
863	        return;
864	      }
865	
866	      if (key.name === "escape") {
867	        buffer = "";
868	        attachments.splice(0);
869	        redraw();
870	        return;
871	      }
872	
873	      if ((key.ctrl && key.name === "v") || key.sequence === "\u0016") {
874	        void pasteClipboard();
875	        return;
876	      }
877	
878	      if (character && character >= " " && !key.ctrl) {
879	        appendText(character);
880	
881	        if (buffer === "/") {
882	          showSuggestions();
883	          return;
884	        }
885	      }
886	    };
887	
888	    emitKeypressEvents(input);
889	    input.setRawMode(true);
890	    input.on("keypress", onKeypress);
891	    redraw();
892	  });
893	}
